const incoming = items[0]?.json ?? {};
const hasIncomingPayload = Object.keys(incoming).length > 0 && Object.keys(incoming).some((key) => key !== 'executionMode');
const payload = incoming.payload ?? incoming.body ?? incoming ?? {};
const executionId = 'exec-' + Date.now();
const traceId = payload.trace_id || 'trace-missing';
const caseId = payload.case_id || 'case-missing';
return [{
  json: {
    payload,
    workflow_context: {
      workflow_mode: 'production_ready',
      environment: 'production',
      source: hasIncomingPayload ? 'incoming_payload' : 'manual_trigger_empty_payload',
      generated_at: new Date().toISOString(),
      workflow_name: 'SOC-Octopus-Agent - Ticket VPN MFA Production',
      workflow_version: '1.0.0',
      observability: {
        started_at_ms: Date.now(),
        execution_id: executionId,
        correlation_id: [caseId, traceId].join(':'),
        trace_id: traceId
      },
      auth_placeholders: {
        x_api_key: incoming.headers?.['x-api-key'] ?? '{{X-API-Key}}',
        authorization_bearer: incoming.headers?.authorization ?? '{{Authorization Bearer}}',
        hmac_signature: incoming.headers?.['x-hmac-signature'] ?? '{{HMAC Signature}}'
      }
    },
    security_controls: {
      external_calls_allowed: false,
      remediation_allowed: false,
      credentials_allowed: false,
      production_allowed: false,
      production_changes_allowed: false,
      human_approval_required: true
    }
  }
}];

function asText(value) {
  if (value === undefined || value === null) return '';
  return String(value).trim();
}
function asBool(value) {
  return value === true || value === 'true';
}
function parseEntities(payload) {
  if (payload.entities && typeof payload.entities === 'object' && !Array.isArray(payload.entities)) return payload.entities;
  const summary = asText(payload.entities_summary);
  const result = {};
  for (const part of summary.split(';')) {
    const [key, ...rest] = part.split('=');
    if (key && rest.length) result[key.trim()] = rest.join('=').trim();
  }
  return result;
}
function normalizeEvidence(payload) {
  if (Array.isArray(payload.evidence)) return payload.evidence.map(asText).filter(Boolean);
  const evidence = asText(payload.evidence_summary || payload.evidence);
  return evidence ? [evidence] : [];
}
return items.map((item) => {
  const payload = item.json.payload ?? {};
  const entities = parseEntities(payload);
  const normalized = {
    case_id: asText(payload.case_id),
    trace_id: asText(payload.trace_id),
    input_type: asText(payload.input_type).toLowerCase(),
    source_system: asText(payload.source_system),
    received_at: asText(payload.received_at),
    severity: asText(payload.severity).toLowerCase(),
    title: asText(payload.title),
    description: asText(payload.description),
    classification_hint: asText(payload.classification_hint).toLowerCase(),
    entities,
    evidence: normalizeEvidence(payload),
    ticket_context: {
      service: asText(payload.service || entities.service).toLowerCase(),
      user: asText(payload.user || entities.user),
      host: asText(payload.host || entities.host),
      source_ip: asText(payload.source_ip || entities.source_ip),
      requester_validated: asBool(payload.requester_validated) || asBool(entities.requester_validated),
      mfa_device_status: asText(payload.mfa_device_status || entities.mfa_device_status).toLowerCase()
    },
    flags: {
      synthetic_payload: asBool(payload.synthetic_payload),
      contains_real_customer_data: asBool(payload.contains_real_customer_data),
      contains_credentials: asBool(payload.contains_credentials),
      human_approval_required_for_action: asBool(payload.human_approval_required_for_action)
    }
  };
  return { json: { ...item.json, normalized, processing_stage: 'normalization', normalization_status: 'completed' } };
});

const allowedInputTypes = new Set(['ticket', 'incident', 'request']);
const allowedSeverities = new Set(['low', 'medium', 'high', 'critical']);
const requiredFields = ['case_id', 'trace_id', 'input_type', 'severity', 'title', 'description'];
const credentialPattern = /(password|passwd|senha|token|secret|client_secret|authorization|bearer)s*[:=]/i;
return items.map((item) => {
  const normalized = item.json.normalized ?? {};
  const ticket = normalized.ticket_context ?? {};
  const missing_fields = requiredFields.filter((field) => !normalized[field]);
  const invalid_fields = [];
  const security = item.json.security_controls ?? {};
  const flags = normalized.flags ?? {};
  const security_violations = [];
  if (normalized.input_type && !allowedInputTypes.has(normalized.input_type)) invalid_fields.push('input_type');
  if (normalized.severity && !allowedSeverities.has(normalized.severity)) invalid_fields.push('severity');
  if (!ticket.user) missing_fields.push('entities.user');
  if (!ticket.service) missing_fields.push('entities.service');
  const searchablePayload = [normalized.title, normalized.description, ...(Array.isArray(normalized.evidence) ? normalized.evidence : []), JSON.stringify(normalized.entities ?? {})].join(' ');
  if (flags.contains_real_customer_data) security_violations.push('contains_real_customer_data');
  if (flags.contains_credentials) security_violations.push('contains_credentials');
  if (credentialPattern.test(searchablePayload)) security_violations.push('credential_like_material_detected');
  if (security.external_calls_allowed) security_violations.push('external_calls_allowed');
  if (security.remediation_allowed) security_violations.push('remediation_allowed');
  if (security.credentials_allowed) security_violations.push('credentials_allowed');
  if (security.production_allowed) security_violations.push('production_allowed');
  if (security.production_changes_allowed) security_violations.push('production_changes_allowed');
  const is_valid = missing_fields.length === 0 && invalid_fields.length === 0 && security_violations.length === 0;
  return {
    json: {
      ...item.json,
      processing_stage: 'validation',
      validation: {
        is_valid,
        status: is_valid ? 'valid' : 'invalid',
        required_fields: [...requiredFields, 'entities.user', 'entities.service'],
        missing_fields,
        invalid_fields,
        security_violations,
        validation_notes: is_valid ? 'Ticket aceito para producao controlada.' : 'Ticket bloqueado antes de classificacao.'
      }
    }
  };
});

return items.map((item) => {
  const normalized = item.json.normalized ?? {};
  const validation = item.json.validation ?? {};
  return {
    json: {
      ...item.json,
      processing_stage: 'controlled_rejection',
      controlled_rejection: {
        rejected: true,
        reason: 'Ticket invalido ou violacao de seguranca detectada antes da classificacao.',
        missing_fields: validation.missing_fields ?? [],
        invalid_fields: validation.invalid_fields ?? [],
        security_violations: validation.security_violations ?? [],
        case_id: normalized.case_id || 'not_available',
        trace_id: normalized.trace_id || 'not_available',
        next_action: 'Corrigir ticket em ambiente controlado e reexecutar manualmente.',
        automated_action_executed: false
      }
    }
  };
});

function includesAny(text, terms) { return terms.some((term) => text.includes(term)); }
function riskFromSeverity(severity) { if (severity === 'critical') return 'critical'; if (severity === 'high') return 'high'; if (severity === 'medium') return 'medium'; return 'low'; }
const routeRules = [
  { route: 'identity', terms: ['identity', 'identidade', 'mfa', '2fa', 'autentic', 'login', 'senha', 'conta', 'dispositivo mfa', 'fator'] },
  { route: 'vpn_access', terms: ['vpn', 'acesso remoto', 'remote access', 'tunel', 'tunnel', 'gateway', 'cliente vpn'] },
  { route: 'endpoint_device', terms: ['endpoint', 'notebook', 'laptop', 'host', 'dispositivo', 'device', 'aplicativo', 'app'] }
];
const specialistsByRoute = { identity: ['identidade_mfa', 'comunicacao_usuario', 'consolidador'], vpn_access: ['vpn_acesso', 'comunicacao_usuario', 'consolidador'], endpoint_device: ['endpoint_dispositivo', 'comunicacao_usuario', 'consolidador'], unknown: ['triagem_soc', 'consolidador'] };
return items.map((item) => {
  const normalized = item.json.normalized ?? {};
  const ticket = normalized.ticket_context ?? {};
  const evidenceText = Array.isArray(normalized.evidence) ? normalized.evidence.join(' ') : '';
  const entitiesText = Object.values(normalized.entities ?? {}).join(' ');
  const corpus = [normalized.classification_hint, normalized.title, normalized.description, ticket.service, ticket.mfa_device_status, evidenceText, entitiesText].join(' ').toLowerCase();
  let probable_root_cause = 'unknown';
  let classification_reason = 'Nenhuma regra local identificou causa provavel com confianca suficiente.';
  let confidence_level = 'low';
  const hint = normalized.classification_hint;
  const directRoute = routeRules.find((rule) => rule.route === hint || (hint === 'vpn' && rule.route === 'vpn_access') || (hint === 'endpoint' && rule.route === 'endpoint_device'));
  if (directRoute) { probable_root_cause = directRoute.route; classification_reason = 'classification_hint indicou rota ' + directRoute.route + '.'; confidence_level = 'high'; }
  else { const matched = routeRules.find((rule) => includesAny(corpus, rule.terms)); if (matched) { probable_root_cause = matched.route; classification_reason = 'Regras locais identificaram termos associados a ' + matched.route + '.'; confidence_level = 'medium'; } }
  if (ticket.mfa_device_status === 'device_changed' && probable_root_cause === 'identity') { confidence_level = 'high'; classification_reason = 'Contexto indica troca de dispositivo MFA associada a falha de autenticacao.'; }
  const risk_level = riskFromSeverity(normalized.severity);
  return { json: { ...item.json, processing_stage: 'classification', classification: { probable_root_cause, routing_key: probable_root_cause, risk_level, risk_score: { critical: 95, high: 80, medium: 55, low: 25 }[risk_level] || 25, confidence_level, confidence_score: { high: 90, medium: 70, low: 45 }[confidence_level] || 45, classification_reason, false_positive_assessment: 'possible', possible_false_positive: true, specialists_recommended: specialistsByRoute[probable_root_cause] ?? specialistsByRoute.unknown } } };
});

